#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
using namespace std;
inline long long read()
{
	long long res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
struct frac{long long p,q;inline bool friend operator < (frac a,frac b){return 1ll*a.p*b.q<1ll*a.q*b.p;}};
const int N=3e5+5;const long long INF=4e18;
int n,d,h=1,t,deq[N];long long dp[N],s[N],sc[N];double K[N];
inline double Cnt(int a,int b){if(s[a]==s[b])return 0;return 1.0*(dp[a]-d*sc[a]-dp[b]+d*sc[b])/(sc[a]-sc[b]);}
int main()
{
// 	freopen("a.in","r",stdin);
	n=read();d=read();rep(1,n,i)s[i]=s[i-1]+read(),sc[i]=sc[i-1]+read();
	deq[t=1]=0; rep(1,n,i)
	{
		int l=1,r=t,mid,res=deq[t];
		while(l<=r){(1.0*s[i]<K[mid=(l+r)>>1])?(r=mid-1,res=deq[mid]):(l=mid+1);}
//		while(h<t&&K[h]<Frac(s[i]))h++;res=deq[h];
		dp[i]=dp[res]+1ll*d*(sc[n]-sc[res])+1ll*s[i]*(sc[i]-sc[res]);
//		printf("%d : %d %d %d %d: ",i,res,s[i],l,deq[3]);rep(1,t-1,i)printf("%.2lf ",1.0*K[i].p/K[i].q);puts("");
		while(h<t&&Cnt(i,deq[t])<K[t-1])t--;K[t]=Cnt(i,deq[t]);deq[++t]=i;
	}
//	rep(1,n,i)printf("%lld ",dp[i]);
//	rep(1,n,i)rep(0,i-1,j)dp[i]=min(dp[i],dp[j]+d*(sc[n]-sc[j])+s[i]*(sc[i]-sc[j]));
	printf("%lld",dp[n]);
}
